public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // ── Constructor + getters ──
        try {
            Weapon w = new Weapon("Sword", 25);
            check("getName()", "Sword", w.getName());
        } catch (Exception e) { fail("getName()", e); }

        try {
            Weapon w = new Weapon("Sword", 25);
            check("getDamage()", "25", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("getDamage()", e); }

        // ── Constructor clamps negative ──
        try {
            Weapon w = new Weapon("Broken Stick", -50);
            check("Constructor clamps -50 to 0",
                  "0", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("Constructor clamps negative", e); }

        // ── Constructor clamps over 100 ──
        try {
            Weapon w = new Weapon("God Sword", 999);
            check("Constructor clamps 999 to 100",
                  "100", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("Constructor clamps over 100", e); }

        // ── setDamage: normal value ──
        try {
            Weapon w = new Weapon("Axe", 40);
            w.setDamage(60);
            check("setDamage(60)",
                  "60", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("setDamage(60)", e); }

        // ── setDamage: clamps negative ──
        try {
            Weapon w = new Weapon("Dagger", 30);
            w.setDamage(-10);
            check("setDamage(-10) clamps to 0",
                  "0", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("setDamage(-10)", e); }

        // ── setDamage: clamps over 100 ──
        try {
            Weapon w = new Weapon("Bow", 20);
            w.setDamage(150);
            check("setDamage(150) clamps to 100",
                  "100", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("setDamage(150)", e); }

        // ── setDamage: boundary values ──
        try {
            Weapon w = new Weapon("Spear", 50);
            w.setDamage(0);
            check("setDamage(0) is valid",
                  "0", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("setDamage(0)", e); }

        try {
            Weapon w = new Weapon("Spear", 50);
            w.setDamage(100);
            check("setDamage(100) is valid",
                  "100", String.valueOf(w.getDamage()));
        } catch (Exception e) { fail("setDamage(100)", e); }

        // ── describe() ──
        try {
            Weapon w = new Weapon("Sword", 25);
            check("describe() — Sword",
                  "Sword deals 25 damage.",
                  w.describe());
        } catch (Exception e) { fail("describe()", e); }

        try {
            Weapon w = new Weapon("Club", -5);
            check("describe() after clamped constructor",
                  "Club deals 0 damage.",
                  w.describe());
        } catch (Exception e) { fail("describe() after clamp", e); }

        // ── Encapsulation: fields are private ──
        try {
            java.lang.reflect.Field f = Weapon.class.getDeclaredField("name");
            check("name is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("name field exists", new Exception("Field 'name' not found"));
        } catch (Exception e) { fail("name is private", e); }

        try {
            java.lang.reflect.Field f = Weapon.class.getDeclaredField("damage");
            check("damage is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("damage field exists", new Exception("Field 'damage' not found"));
        } catch (Exception e) { fail("damage is private", e); }
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e.getMessage()); failed++;
    }
}
